patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 659b4c30a58a..e03905d29b76 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -1532,6 +1532,7 @@ public:
   /// Returns true if \p Op should be considered invariant and if it is
   /// trivially hoistable.
   bool shouldConsiderInvariant(Value *Op);
+  bool shouldConsiderInvariant(Value *Op, SmallPtrSetImpl<const Value*> &Visited);

 private:
   unsigned NumPredStores = 0;
@@ -6385,14 +6386,26 @@ void LoopVectorizationCostModel::setVectorizedCallDecision(ElementCount VF) {
 }

 bool LoopVectorizationCostModel::shouldConsiderInvariant(Value *Op) {
+  SmallPtrSet<const Value*, 8> Visited;
+  return shouldConsiderInvariant(Op, Visited);
+}
+
+bool LoopVectorizationCostModel::shouldConsiderInvariant(Value *Op, SmallPtrSetImpl<const Value*> &Visited) {
   if (!Legal->isInvariant(Op))
     return false;
   // Consider Op invariant, if it or its operands aren't predicated
   // instruction in the loop. In that case, it is not trivially hoistable.
-  return !isa<Instruction>(Op) || !TheLoop->contains(cast<Instruction>(Op)) ||
-         (!isPredicatedInst(cast<Instruction>(Op)) &&
-          all_of(cast<Instruction>(Op)->operands(),
-                 [this](Value *Op) { return shouldConsiderInvariant(Op); }));
+  if (!isa<Instruction>(Op) || !TheLoop->contains(cast<Instruction>(Op)))
+    return true;
+  if (isPredicatedInst(cast<Instruction>(Op)))
+    return false;
+  // Avoid infinite recursion on cycles in the data graph.
+  if (!Visited.insert(Op).second)
+    return true;
+  return all_of(cast<Instruction>(Op)->operands(),
+                [this, &Visited](Value *V) {
+                  return shouldConsiderInvariant(V, Visited);
+                });
 }

